// Minimal, dependency-free demo driver for the mce-wasm bindings.
//
// It imports the wasm-pack `--target web` output from ../pkg (generated by
// `wasm-pack build bindings/wasm --target web`; see README in this directory).
// No bundler or framework is involved — this is a plain ES module.

import init, { Game } from "../pkg/mce_wasm.js";

const $ = (id) => document.getElementById(id);
const variantSel = $("variant");
const fenEl = $("fen");
const statusEl = $("status");
const errEl = $("err");
const movesEl = $("moves");
const undoBtn = $("undo");

let game = null;
// Stack of FENs we have visited, so "Undo" can step back one ply.
let history = [];

function showError(e) {
  errEl.textContent = e && e.message ? e.message : String(e);
}

function clearError() {
  errEl.textContent = "";
}

function describeOutcome(out) {
  if (!out) return null;
  if (out.kind === "draw") {
    return `Draw${out.reason ? ` (${out.reason})` : ""}`;
  }
  const who = out.winner ? out.winner[0].toUpperCase() + out.winner.slice(1) : "?";
  return `${who} wins${out.reason ? ` (${out.reason})` : ""}`;
}

// Try to render moves as SAN (standard / Chess960); fall back to UCI for the
// variants that have no SAN surface.
function moveLabels(uciMoves) {
  let sans = null;
  try {
    sans = game.legalMovesSan();
  } catch {
    sans = null;
  }
  return uciMoves.map((uci, i) => (sans && sans[i] ? sans[i] : uci));
}

function render() {
  clearError();
  fenEl.textContent = game.fen();

  const out = game.outcome();
  const parts = [`${game.turn()} to move`];
  if (game.isCheck()) parts.push(game.isCheckmate() ? "checkmate" : "check");
  const result = describeOutcome(out);
  statusEl.innerHTML = result
    ? `<span class="warn">${result}</span>`
    : parts.join(" — ");

  movesEl.innerHTML = "";
  if (out) {
    undoBtn.disabled = history.length === 0;
    return;
  }

  const uciMoves = game.legalMoves();
  const labels = moveLabels(uciMoves);
  uciMoves.forEach((uci, i) => {
    const b = document.createElement("button");
    b.textContent = labels[i];
    b.title = uci;
    b.addEventListener("click", () => playMove(uci));
    movesEl.appendChild(b);
  });
  undoBtn.disabled = history.length === 0;
}

function playMove(uci) {
  try {
    history.push(game.fen());
    game.push(uci);
    render();
  } catch (e) {
    history.pop();
    showError(e);
  }
}

function newGame() {
  try {
    const variant = variantSel.value;
    game = Game.startpos(variant);
    history = [];
    render();
  } catch (e) {
    showError(e);
  }
}

function randomMove() {
  if (!game || game.outcome()) return;
  const moves = game.legalMoves();
  if (moves.length === 0) return;
  playMove(moves[Math.floor(Math.random() * moves.length)]);
}

function undo() {
  if (history.length === 0) return;
  const fen = history.pop();
  try {
    game = Game.fromFen(fen, variantSel.value);
    render();
  } catch (e) {
    showError(e);
  }
}

$("reset").addEventListener("click", newGame);
$("random").addEventListener("click", randomMove);
undoBtn.addEventListener("click", undo);
variantSel.addEventListener("change", newGame);

// Boot: load the wasm module, then start a fresh standard game.
init()
  .then(newGame)
  .catch((e) => {
    showError(
      "Failed to load wasm. Build it first: " +
        "wasm-pack build bindings/wasm --target web (see www/README.md). " +
        (e && e.message ? e.message : ""),
    );
  });
